\section{Worked Examples}\label{sec:examples}

\needspace{12\baselineskip}
\begin{examplebox}{Calculating Area Between $y = x^2$ and $y = \sin(x)$}
\textbf{Problem:} Find the area between the curves $y = x^2$ and $y = \sin(x)$ from $x = 0$ to $x = \pi$.\\
\textbf{Given:}
\begin{itemize}
    \item Function 1: $y = x^2$
    \item Function 2: $y = \sin(x)$
    \item Interval: $[0, \pi]$
\end{itemize}
\textbf{Required:} Calculate the area between the curves.
\end{examplebox}
\begin{solutionbox}
\textbf{Step 1: Identify the intersection points by solving $x^2 = \sin(x)$.}\\
\begin{align*}
    &\text{Intersection at } x = 0 \text{ and } x = \pi.
\end{align*}
\textbf{Step 2: Determine which function is on top over the interval.}\\
\begin{align*}
    &\text{For } x \in [0, \pi], \sin(x) \text{ is above } x^2.
\end{align*}
\textbf{Step 3: Set up the integral of the difference between the functions.}\\
\begin{align*}
    A &= \int_{0}^{\pi} (\sin(x) - x^2) \, dx
\end{align*}
\textbf{Step 4: Evaluate the integral using appropriate techniques.}\\
\begin{align*}
    A &= \left[-\cos(x) - \frac{x^3}{3}\right]_0^\pi
\end{align*}
\textbf{Step 5: Substitute the limits into the evaluated integral.}\\
\begin{align*}
    A &= [-(-1) - \frac{\pi^3}{3}] - [-(1) - 0]
\end{align*}
\[\boxed{2 - \frac{\pi^3}{3}} \text{ square units}\]
\end{solutionbox}
\begin{notebox}
Ensure students recognize which function is on top. A common mistake is integrating the functions in the wrong order, which would give a negative area.
\end{notebox}

