\needspace{6\baselineskip}
\section*{Solutions to Exercises}\nopagebreak[4]

\begin{samepage}
\needspace{10\baselineskip}
\begin{solutionbox}
\textbf{Exercise 1: Integration by Parts for \( \int x^2 e^x \, dx \)}\\[0.5em]
\textbf{Step 1: Choose \( u \) and \( dv \)}\\
Let \( u = x^2 \) and \( dv = e^x \, dx \). Then \( du = 2x \, dx \) and \( v = e^x \).\\
\textbf{Step 2: Apply Integration by Parts Formula}\\
\begin{align*}
\int x^2 e^x \, dx &= x^2 e^x - \int 2x e^x \, dx \\
&= x^2 e^x - 2 \left( \int x e^x \, dx \right)
\end{align*}
\textbf{Step 3: Solve Remaining Integral}\\
Let \( u = x \) and \( dv = e^x \, dx \). Then \( du = dx \) and \( v = e^x \).\\
\begin{align*}
\int x e^x \, dx &= x e^x - \int e^x \, dx \\
&= x e^x - e^x
\end{align*}
Substituting back, we have:
\begin{align*}
\int x^2 e^x \, dx &= x^2 e^x - 2(x e^x - e^x) \\
&= x^2 e^x - 2x e^x + 2e^x + C
\end{align*}
\[\boxed{x^2 e^x - 2x e^x + 2e^x + C}\]
\end{solutionbox}
\end{samepage}

