\section*{Solutions to Exercises}\nopagebreak[4]

\begin{samepage}
\needspace{10\baselineskip}
\begin{solutionbox}
\textbf{Exercise 1: Evaluate $\int_{2}^{\infty} \frac{1}{x^3} \, dx$}\\[0.5em]
\textbf{Step 1: Express the integral as a limit}\\
Set up the integral using a limit to address the infinite upper bound.
\begin{align*}
\lim_{b \to \infty} \int_{2}^{b} \frac{1}{x^3} \, dx
\end{align*}

\textbf{Step 2: Find the antiderivative}\\
Integrate $\frac{1}{x^3}$ to find the antiderivative.
\begin{align*}
-\frac{1}{2x^2}
\end{align*}

\textbf{Step 3: Evaluate the bounds}\\
Substitute the bounds into the antiderivative.
\begin{align*}
\left[-\frac{1}{2x^2}\right]_{2}^{b} = -\frac{1}{2b^2} + \frac{1}{8}
\end{align*}

\textbf{Step 4: Take the limit}\\
Calculate the limit as $b$ approaches infinity.
\begin{align*}
\lim_{b \to \infty} \left(-\frac{1}{2b^2} + \frac{1}{8}\right) = \frac{1}{8}
\end{align*}

\[\boxed{\frac{1}{8}}\]
\end{solutionbox}
\end{samepage}

