\begin{samepage}
\needspace{10\baselineskip}
\begin{solutionbox}
\textbf{Exercise 3: Construction Project Schedule Outcome}\\[0.5em]
\textbf{Step 1: Identify outcomes and probabilities}\\
On-time: $P_1 = 0.50$, $V_1 = +\$30{,}000$\\
One month late: $P_2 = 0.35$, $V_2 = -\$10{,}000$\\
Two months late: $P_3 = 0.15$, $V_3 = -\$40{,}000$

\textbf{Step 2: Calculate expected value}
\begin{align*}
EV &= (0.50 \times \$30{,}000) + (0.35 \times (-\$10{,}000)) + (0.15 \times (-\$40{,}000)) \\
&= \$15{,}000 - \$3{,}500 - \$6{,}000 \\
&= \$5{,}500
\end{align*}
\[\boxed{EV = \$5{,}500 \text{ (expected net bonus)}}\]
\end{solutionbox}
\end{samepage}

\begin{samepage}
\needspace{10\baselineskip}
\begin{solutionbox}
\textbf{Exercise 4: Converting Probabilities to Decimals}\\[0.5em]
\textbf{Step 1: Convert each percentage}
\begin{align*}
45\% &= 0.45 \\
30\% &= 0.30 \\
18\% &= 0.18 \\
7\% &= 0.07
\end{align*}

\textbf{Step 2: Verify sum equals unity}
\begin{align*}
\sum P_i &= 0.45 + 0.30 + 0.18 + 0.07 \\
&= 1.00 \checkmark
\end{align*}
\[\boxed{\text{Decimals: } 0.45, 0.30, 0.18, 0.07 \text{ (sum} = 1.00\text{)}}\]
\end{solutionbox}
\end{samepage}

\begin{samepage}
\needspace{10\baselineskip}
\begin{solutionbox}
\textbf{Exercise 5: Renewable Energy Project EMV}\\[0.5em]
\textbf{Step 1: Identify values}\\
$V_1 = \$800{,}000$, $P_1 = 0.3$\\
$V_2 = \$400{,}000$, $P_2 = 0.5$\\
$V_3 = \$100{,}000$, $P_3 = 0.2$

\textbf{Step 2: Calculate EMV}
\begin{align*}
EMV &= (0.3 \times \$800{,}000) + (0.5 \times \$400{,}000) + (0.2 \times \$100{,}000) \\
&= \$240{,}000 + \$200{,}000 + \$20{,}000 \\
&= \$460{,}000
\end{align*}
\[\boxed{EMV = \$460{,}000}\]
\end{solutionbox}
\end{samepage}

\begin{samepage}
\needspace{10\baselineskip}
\begin{solutionbox}
\textbf{Exercise 6: Variance of Renewable Energy Project}\\[0.5em]
\textbf{Step 1: Use EMV from Exercise 5}\\
$EMV = \$460{,}000$

\textbf{Step 2: Calculate squared deviations}
\begin{align*}
(V_1 - EMV)^2 &= (\$800{,}000 - \$460{,}000)^2 = (\$340{,}000)^2 = 115.6 \times 10^9 \\
(V_2 - EMV)^2 &= (\$400{,}000 - \$460{,}000)^2 = (-\$60{,}000)^2 = 3.6 \times 10^9 \\
(V_3 - EMV)^2 &= (\$100{,}000 - \$460{,}000)^2 = (-\$360{,}000)^2 = 129.6 \times 10^9
\end{align*}

\textbf{Step 3: Calculate variance}
\begin{align*}
\sigma^2 &= (0.3 \times 115.6 \times 10^9) + (0.5 \times 3.6 \times 10^9) + (0.2 \times 129.6 \times 10^9) \\
&= 34.68 \times 10^9 + 1.8 \times 10^9 + 25.92 \times 10^9 \\
&= 62.4 \times 10^9
\end{align*}
\[\boxed{\sigma^2 = 62.4 \times 10^9 \text{ dollars}^2}\]
\end{solutionbox}
\end{samepage}

\begin{samepage}
\needspace{10\baselineskip}
\begin{solutionbox}
\textbf{Exercise 7: Standard Deviation and Risk Interpretation}\\[0.5em]
\textbf{Step 1: Calculate standard deviation from variance}
\begin{align*}
\sigma &= \sqrt{62.4 \times 10^9} \\
&= \sqrt{62{,}400{,}000{,}000} \\
&\approx \$249{,}800
\end{align*}

\textbf{Step 2: Interpret the result}\\
The standard deviation of approximately \$249,800 indicates that actual returns are expected to deviate from the EMV of \$460,000 by roughly this amount on average. This represents significant variability, suggesting moderate-to-high risk.

\textbf{Step 3: Calculate coefficient of variation}
\begin{align*}
CV &= \frac{\sigma}{EMV} = \frac{\$249{,}800}{\$460{,}000} \approx 0.543 = 54.3\%
\end{align*}
\[\boxed{\sigma \approx \$249{,}800 \text{ (CV} = 54.3\%\text{)}}\]
\end{solutionbox}
\end{samepage}

\begin{samepage}
\needspace{10\baselineskip}
\begin{solutionbox}
\textbf{Exercise 8: Coefficient of Variation Comparison}\\[0.5em]
\textbf{Step 1: Calculate CV for each project}
\begin{align*}
CV_{\alpha} &= \frac{\$45{,}000}{\$120{,}000} = 0.375 = 37.5\% \\[0.5em]
CV_{\beta} &= \frac{\$90{,}000}{\$150{,}000} = 0.600 = 60.0\% \\[0.5em]
CV_{\gamma} &= \frac{\$50{,}000}{\$135{,}000} = 0.370 = 37.0\%
\end{align*}

\textbf{Step 2: Compare and recommend}\\
Project Gamma has the lowest CV (37.0\%), indicating the best risk-adjusted return. Although Project Beta has the highest EMV, its CV of 60\% indicates substantially higher risk per dollar of expected return.
\[\boxed{\text{Recommend Project Gamma (CV} = 37.0\%\text{)}}\]
\end{solutionbox}
\end{samepage}

\begin{samepage}
\needspace{10\baselineskip}
\begin{solutionbox}
\textbf{Exercise 9: Technology Investment Analysis}\\[0.5em]
\textbf{Step 1: Calculate EMV}
\begin{align*}
EMV &= (0.10 \times \$2{,}000{,}000) + (0.30 \times \$500{,}000) \\
&\quad + (0.40 \times \$100{,}000) + (0.20 \times (-\$300{,}000)) \\
&= \$200{,}000 + \$150{,}000 + \$40{,}000 - \$60{,}000 \\
&= \$330{,}000
\end{align*}

\textbf{Step 2: Calculate variance}
\begin{align*}
\sigma^2 &= 0.10(2{,}000{,}000 - 330{,}000)^2 + 0.30(500{,}000 - 330{,}000)^2 \\
&\quad + 0.40(100{,}000 - 330{,}000)^2 + 0.20(-300{,}000 - 330{,}000)^2 \\
&= 0.10(1{,}670{,}000)^2 + 0.30(170{,}000)^2 + 0.40(-230{,}000)^2 + 0.20(-630{,}000)^2 \\
&= 278.89 \times 10^9 + 8.67 \times 10^9 + 21.16 \times 10^9 + 79.38 \times 10^9 \\
&= 388.1 \times 10^9
\end{align*}

\textbf{Step 3: Calculate standard deviation and CV}
\begin{align*}
\sigma &= \sqrt{388.1 \times 10^9} \approx \$623{,}000 \\
CV &= \frac{\$623{,}000}{\$330{,}000} \approx 1.89
\end{align*}

\textbf{Step 4: Decision}\\
Since $CV = 1.89 > 1.0$, the investment exceeds the firm's risk threshold.
\[\boxed{EMV = \$330{,}000, \sigma \approx \$623{,}000, CV = 1.89 \text{ — Do not proceed}}\]
\end{solutionbox}
\end{samepage}

\begin{samepage}
\needspace{10\baselineskip}
\begin{solutionbox}
\textbf{Exercise 10: Decision Tree and Optimal Decision}\\[0.5em]
\textbf{Step 1: Calculate EV for Product A}
\begin{align*}
EV_A &= (0.60 \times \$500{,}000) + (0.40 \times (-\$50{,}000)) \\
&= \$300{,}000 - \$20{,}000 \\
&= \$280{,}000
\end{align*}

\textbf{Step 2: Calculate EV for Product B}
\begin{align*}
EV_B &= (0.80 \times \$300{,}000) + (0.20 \times \$100{,}000) \\
&= \$240{,}000 + \$20{,}000 \\
&= \$260{,}000
\end{align*}

\textbf{Step 3: Identify value of doing nothing}\\
$EV_{\text{nothing}} = \$150{,}000$ (certain)

\textbf{Step 4: Compare all alternatives}
\begin{align*}
EV_A &= \$280{,}000 \\
EV_B &= \$260{,}000 \\
EV_{\text{nothing}} &= \$150{,}000
\end{align*}

\textbf{Step 5: Select optimal decision}\\
Product A has the highest expected value at \$280,000.
\[\boxed{\text{Optimal decision: Launch Product A (EV} = \$280{,}000\text{)}}\]
\end{solutionbox}
\end{samepage}

