]
\addplot[color=blue, line width=1.5pt, domain=0:10, samples=50] {10000*(1+0.05*x)};
\addlegendentry{Simple Interest (5\%)}
\addplot[color=red, line width=1.5pt, domain=0:10, samples=50] {10000*(1.05)^x};
\addlegendentry{Compound Interest (5\%)}
