    \node[block, right=of start] (analyze) {Analyze Trends};
    \node[block, right=of analyze] (project) {Project Returns};
    \node[block, below=of project] (risk) {Assess Risk};
    \node[block, left=of risk] (compare) {Compare Strategies};
    \node[block, left=of compare] (recommend) {Recommend};

    \draw[arrow] (start) -- (analyze);
    \draw[arrow] (analyze) -- (project);
