\section*{Worked Examples}
\begin{samepage}
\needspace{8\baselineskip}
\begin{examplebox}{Calculating Present Value}
Calculate the present value of \$100 that will be received after 5 years assuming an annual discount rate of 5\%.
\begin{itemize}
    \item \textbf{Given Information:}
    \begin{itemize}
        \item Future Value (FV): \$100
        \item Number of years (n): 5
        \item Discount rate (r): 5\%
    \end{itemize}
    \item \textbf{Required:} Present Value (PV)
\end{itemize}
\end{examplebox}

\begin{solutionbox}
\textbf{Solution Steps:}
\begin{itemize}
    \item \textbf{Step 1:} Apply the formula for present value.
    \begin{itemize}
        \item \textbf{Explanation:} The present value formula is used to determine the value of money at present compared to the future.
        \item \textbf{Formula:} 
        \[
        PV = \frac{FV}{(1 + r)^n}
        \]
        \item \textbf{Calculation:} 
        \[
        PV = \frac{100}{(1 + 0.05)^5} = \frac{100}{1.276} \approx 78.35
        \]
    \end{itemize}
\end{itemize}
\textbf{Final Answer:} \(\boxed{78.35}\) \\
\textbf{Teaching Notes:} Common mistake: not adjusting the rate to a decimal before calculations. Key insight: The discount rate significantly affects the present value.
\end{solutionbox}
\end{samepage}

