\section*{Solutions to Exercises}\label{sec:solutions}
\nopagebreak[4]
\begin{samepage}
\needspace{10\baselineskip}
\begin{solutionbox}
\textbf{Exercise 6: Calculate NPV}\\[0.5em]
\textbf{Step 1: Calculate Present Values}\\
Calculate the present value for each year's cash flow using the formula $PV = \frac{CF}{(1 + r)^n}$.

\begin{align*}
PV_{\text{Year 1}} &= \frac{\$20,000}{(1 + 0.10)^1} = \$18,181.82 \\
PV_{\text{Year 2}} &= \frac{\$20,000}{(1 + 0.10)^2} = \$16,528.93 \\
PV_{\text{Year 3}} &= \frac{\$20,000}{(1 + 0.10)^3} = \$15,026.30 \\
PV_{\text{Year 4}} &= \frac{\$20,000}{(1 + 0.10)^4} = \$13,660.27 \\
PV_{\text{Year 5}} &= \frac{\$20,000}{(1 + 0.10)^5} = \$12,418.43
\end{align*}

\textbf{Step 2: Sum the Present Values}\\
Add the present values to get the total present value of the cash flows.

\begin{align*}
\text{Total PV} &= \$18,181.82 + \$16,528.93 + \$15,026.30 + \$13,660.27 + \$12,418.43 \\
&= \$75,815.75
\end{align*}

\textbf{Step 3: Calculate Net Present Value (NPV)}\\
Subtract the initial investment from the total present value of cash flows.

\begin{align*}
NPV &= \text{Total PV} - \text{Initial Investment} \\
&= \$75,815.75 - \$100,000 \\
&= -\$24,184.25
\end{align*}

\[\boxed{\text{The NPV of the project is -\$24,184.25, indicating it may not be financially viable.}}\]
\end{solutionbox}
\end{samepage}

