\begin{axis}[
    axis lines=middle,
    xlabel={$x$},
    ylabel={$y$},
    xmin=0, xmax=8,
    ymin=0, ymax=14,
    xtick={0,2,4,6,8},
    ytick={0,2,4,6,8,10,12,14},
    grid=both,
    grid style={line width=0.2pt, draw=gray!30},
    width=9cm,
    height=7cm
]
\addplot[only marks, mark=*, mark size=3pt, blue] coordinates {(2,3) (6,11)};
\addplot[thick, blue, domain=0:8] {2*x - 1};
\draw[thick, red, ->] (axis cs:2,3) -- (axis cs:6,3) node[midway, below] {$\Delta x = 4$};
\draw[thick, red, ->] (axis cs:6,3) -- (axis cs:6,11) node[midway, right] {$\Delta y = 8$};
\node[below left] at (axis cs:2,3) {Point A $(2, 3)$};
\node[above right] at (axis cs:6,11) {Point B $(6, 11)$};
\draw[thick, orange, dashed] (axis cs:2,3) -- (axis cs:6,3) -- (axis cs:6,11) -- cycle;
\end{axis}
\end{tikzpicture}
\caption{Figure 1: Concept Diagram of Gradient Slope showing the slope triangle with $\Delta x$ and $\Delta y$ labeled.}
\end{figure}

\begin{table}[H]
\centering
\caption{Figure 2: Summary Table of Calculations}
\begin{tabular}{@{}clc@{}}
\toprule
\textbf{Step} & \textbf{Description} & \textbf{Value} \\
\midrule
1 & $\Delta x = 6 - 2$ & 4 \\
2 & $\Delta y = 11 - 3$ & 8 \\
3 & Slope formula $m = \Delta y / \Delta x$ & --- \\
4 & Calculated slope $m = 8/4$ & 2 \\
5 & Final slope value $m$ & 2 \\
\bottomrule
\end{tabular}
\end{table}
\end{examplebox}

\begin{solutionbox}
\textbf{Step 1: Calculate Change in $x$}\\
The $x$-coordinate of Point 1 is $2$, and the $x$-coordinate of Point 2 is $6$. We calculate $\Delta x$ as the difference between these coordinates.
\begin{align*}
\text{Formula:} \quad \Delta x &= x_2 - x_1 \\
\text{Substitution:} \quad \Delta x &= 6 - 2 \\
\text{Result:} \quad \Delta x &= 4
\end{align*}
The value $\Delta x = 4$ represents the horizontal change between the two points.

\textbf{Step 2: Calculate Change in $y$}\\
The $y$-coordinate of Point 1 is $3$, and the $y$-coordinate of Point 2 is $11$. We calculate $\Delta y$ as the difference between these coordinates.
\begin{align*}
\text{Formula:} \quad \Delta y &= y_2 - y_1 \\
\text{Substitution:} \quad \Delta y &= 11 - 3 \\
\text{Result:} \quad \Delta y &= 8
\end{align*}
The value $\Delta y = 8$ represents the vertical change between the two points.

\textbf{Step 3: Calculate Slope}\\
Using the slope formula, we divide the change in $y$ by the change in $x$ to determine the gradient.
\begin{align*}
\text{Formula:} \quad m &= \frac{\Delta y}{\Delta x} \\
\text{Substitution:} \quad m &= \frac{8}{4} \\
\text{Result:} \quad m &= 2
\end{align*}
The slope indicates the steepness of the line connecting the two points.

\[\boxed{m = 2}\]
\end{solutionbox}

\begin{notebox}
\textbf{Key Takeaways:}
\begin{itemize}[nosep]
\item Slope measures the steepness of a line
\item A positive slope indicates an upward trend from left to right
\item Slope is calculated using changes in $y$ and $x$ coordinates
\end{itemize}
\textit{Verification:} Double-check calculations using different coordinate pairs or by reversing the order of subtraction (both numerator and denominator).
\end{notebox}
\end{samepage}

