\section*{Solutions to Exercises}
\nopagebreak[4]

\begin{samepage}
\needspace{10\baselineskip}
\begin{solutionbox}
\textbf{Exercise 1: Slope through $(1, 4)$ and $(5, 12)$}\\[0.5em]
\textbf{Step 1: Identify the coordinates}\\
We have Point 1: $(x_1, y_1) = (1, 4)$ and Point 2: $(x_2, y_2) = (5, 12)$.

\textbf{Step 2: Calculate $\Delta y$}\\
\begin{align*}
\Delta y &= y_2 - y_1 = 12 - 4 = 8
\end{align*}

\textbf{Step 3: Calculate $\Delta x$}\\
\begin{align*}
\Delta x &= x_2 - x_1 = 5 - 1 = 4
\end{align*}

\textbf{Step 4: Calculate the slope}\\
\begin{align*}
m &= \frac{\Delta y}{\Delta x} = \frac{8}{4} = 2
\end{align*}

\[\boxed{m = 2}\]
\end{solutionbox}
\end{samepage}

\begin{samepage}
\needspace{10\baselineskip}
\begin{solutionbox}
\textbf{Exercise 2: Gradient through $(-2, 5)$ and $(4, -1)$}\\[0.5em]
\textbf{Step 1: Identify the coordinates}\\
We have Point 1: $(x_1, y_1) = (-2, 5)$ and Point 2: $(x_2, y_2) = (4, -1)$.

\textbf{Step 2: Calculate $\Delta y$}\\
\begin{align*}
\Delta y &= y_2 - y_1 = -1 - 5 = -6
\end{align*}

\textbf{Step 3: Calculate $\Delta x$}\\
\begin{align*}
\Delta x &= x_2 - x_1 = 4 - (-2) = 4 + 2 = 6
\end{align*}

\textbf{Step 4: Calculate the slope}\\
\begin{align*}
m &= \frac{\Delta y}{\Delta x} = \frac{-6}{6} = -1
\end{align*}

\[\boxed{m = -1}\]
\end{solutionbox}
\end{samepage}

\begin{samepage}
\needspace{10\baselineskip}
\begin{solutionbox}
\textbf{Exercise 3: Slope through origin and $(8, 6)$}\\[0.5em]
\textbf{Step 1: Identify the coordinates}\\
We have Point 1: $(x_1, y_1) = (0, 0)$ and Point 2: $(x_2, y_2) = (8, 6)$.

\textbf{Step 2: Calculate $\Delta y$}\\
\begin{align*}
\Delta y &= y_2 - y_1 = 6 - 0 = 6
\end{align*}

\textbf{Step 3: Calculate $\Delta x$}\\
\begin{align*}
\Delta x &= x_2 - x_1 = 8 - 0 = 8
\end{align*}

\textbf{Step 4: Calculate the slope}\\
\begin{align*}
m &= \frac{\Delta y}{\Delta x} = \frac{6}{8} = \frac{3}{4}
\end{align*}

\[\boxed{m = \frac{3}{4}}\]
\end{solutionbox}
\end{samepage}

\begin{samepage}
\needspace{10\baselineskip}
\begin{solutionbox}
\textbf{Exercise 4: Roof pitch from $(0, 4)$ to $(12, 7)$}\\[0.5em]
\textbf{Step 1: Identify the coordinates}\\
We have Point 1: $(x_1, y_1) = (0, 4)$ and Point 2: $(x_2, y_2) = (12, 7)$.

\textbf{Step 2: Calculate the rise}\\
\begin{align*}
\text{Rise} &= y_2 - y_1 = 7 - 4 = 3
\end{align*}

\textbf{Step 3: Calculate the run}\\
\begin{align*}
\text{Run} &= x_2 - x_1 = 12 - 0 = 12
\end{align*}

\textbf{Step 4: Calculate the pitch (slope)}\\
\begin{align*}
m &= \frac{\text{Rise}}{\text{Run}} = \frac{3}{12} = \frac{1}{4} = 0.25
\end{align*}

\[\boxed{m = \frac{1}{4} = 0.25}\]
\end{solutionbox}
\end{samepage}

\begin{samepage}
\needspace{10\baselineskip}
\begin{solutionbox}
\textbf{Exercise 5: Wheelchair ramp gradient}\\[0.5em]
\textbf{Step 1: Identify the coordinates}\\
We have Point 1: $(x_1, y_1) = (0, 0)$ and Point 2: $(x_2, y_2) = (24, 2)$.

\textbf{Step 2: Calculate the rise}\\
\begin{align*}
\text{Rise} &= y_2 - y_1 = 2 - 0 = 2
\end{align*}

\textbf{Step 3: Calculate the run}\\
\begin{align*}
\text{Run} &= x_2 - x_1 = 24 - 0 = 24
\end{align*}

\textbf{Step 4: Calculate the gradient}\\
\begin{align*}
m &= \frac{\text{Rise}}{\text{Run}} = \frac{2}{24} = \frac{1}{12}
\end{align*}

\textbf{Step 5: Express as a ratio}\\
The gradient $\frac{1}{12}$ can be expressed as the ratio $1:12$.

\[\boxed{m = \frac{1}{12} \text{ or } 1:12}\]
\end{solutionbox}
\end{samepage}

\begin{samepage}
\needspace{10\baselineskip}
\begin{solutionbox}
\textbf{Exercise 6: Slope of line $PQ$ and interpretation}\\[0.5em]
\textbf{Step 1: Identify the coordinates}\\
We have $P(x_1, y_1) = (-3, -2)$ and $Q(x_2, y_2) = (5, 6)$.

\textbf{Step 2: Calculate $\Delta y$}\\
\begin{align*}
\Delta y &= y_2 - y_1 = 6 - (-2) = 6 + 2 = 8
\end{align*}

\textbf{Step 3: Calculate $\Delta x$}\\
\begin{align*}
\Delta x &= x_2 - x_1 = 5 - (-3) = 5 + 3 = 8
\end{align*}

\textbf{Step 4: Calculate the slope}\\
\begin{align*}
m &= \frac{\Delta y}{\Delta x} = \frac{8}{8} = 1
\end{align*}

\textbf{Step 5: Interpretation}\\
Since $m = 1 > 0$, the line rises from left to right. The slope of $1$ means the line rises at a $45°$ angle.

\[\boxed{m = 1 \text{ (line rises from left to right)}}\]
\end{solutionbox}
\end{samepage}

\begin{samepage}
\needspace{10\baselineskip}
\begin{solutionbox}
\textbf{Exercise 7: Drainage pipe slope and interpretation}\\[0.5em]
\textbf{Step 1: Identify the coordinates}\\
We have $A(x_1, y_1) = (2, 8)$ and $B(x_2, y_2) = (14, 5)$.

\textbf{Step 2: Calculate $\Delta y$}\\
\begin{align*}
\Delta y &= y_2 - y_1 = 5 - 8 = -3
\end{align*}

\textbf{Step 3: Calculate $\Delta x$}\\
\begin{align*}
\Delta x &= x_2 - x_1 = 14 - 2 = 12
\end{align*}

\textbf{Step 4: Calculate the slope}\\
\begin{align*}
m &= \frac{\Delta y}{\Delta x} = \frac{-3}{12} = -\frac{1}{4} = -0.25
\end{align*}

\textbf{Step 5: Interpretation}\\
The negative slope indicates that the pipe descends from point $A$ to point $B$. Water will flow downhill from $A$ (higher elevation) to $B$ (lower elevation) due to gravity.

\[\boxed{m = -\frac{1}{4} \text{ (pipe descends; water flows from } A \text{ to } B\text{)}}\]
\end{solutionbox}
\end{samepage}

\begin{samepage}
\needspace{10\baselineskip}
\begin{solutionbox}
\textbf{Exercise 8: Collinearity of three points}\\[0.5em]
\textbf{Step 1: Calculate slope between $A(1, 2)$ and $B(4, 8)$}\\
\begin{align*}
m_{AB} &= \frac{y_B - y_A}{x_B - x_A} = \frac{8 - 2}{4 - 1} = \frac{6}{3} = 2
\end{align*}

\textbf{Step 2: Calculate slope between $B(4, 8)$ and $C(7, 14)$}\\
\begin{align*}
m_{BC} &= \frac{y_C - y_B}{x_C - x_B} = \frac{14 - 8}{7 - 4} = \frac{6}{3} = 2
\end{align*}

\textbf{Step 3: Compare slopes and conclude}\\
Since $m_{AB} = m_{BC} = 2$, the slopes are equal. This means all three points lie on the same straight line.

\[\boxed{m_{AB} = m_{BC} = 2 \text{; the points are collinear}}\]
\end{solutionbox}
\end{samepage}

\begin{samepage}
\needspace{10\baselineskip}
\begin{solutionbox}
\textbf{Exercise 9: Highway grade as a percentage}\\[0.5em]
\textbf{Step 1: Identify the coordinates}\\
Point 1: $(x_1, y_1) = (0 \text{ km}, 120 \text{ m})$ and Point 2: $(x_2, y_2) = (1.5 \text{ km}, 180 \text{ m})$.

\textbf{Step 2: Calculate the rise (change in elevation)}\\
\begin{align*}
\text{Rise} &= 180 - 120 = 60 \text{ m}
\end{align*}

\textbf{Step 3: Calculate the run (horizontal distance)}\\
Convert to consistent units: $1.5 \text{ km} = 1500 \text{ m}$
\begin{align*}
\text{Run} &= 1500 - 0 = 1500 \text{ m}
\end{align*}

\textbf{Step 4: Calculate the slope}\\
\begin{align*}
m &= \frac{\text{Rise}}{\text{Run}} = \frac{60}{1500} = \frac{1}{25} = 0.04
\end{align*}

\textbf{Step 5: Convert to percentage}\\
\begin{align*}
\text{Grade} &= 0.04 \times 100\% = 4\%
\end{align*}

\[\boxed{\text{Grade} = 4\%}\]
\end{solutionbox}
\end{samepage}

\begin{samepage}
\needspace{10\baselineskip}
\begin{solutionbox}
\textbf{Exercise 10: Finding a point given slope}\\[0.5em]
\textbf{Step 1: Identify known information}\\
Slope $m = \frac{3}{4}$, known point $(x_1, y_1) = (2, 5)$, and $x_2 = 10$.

\textbf{Step 2: Set up the slope equation}\\
Using the slope formula:
\begin{align*}
m &= \frac{y_2 - y_1}{x_2 - x_1}
\end{align*}

\textbf{Step 3: Substitute known values}\\
\begin{align*}
\frac{3}{4} &= \frac{y_2 - 5}{10 - 2} \\[0.5em]
\frac{3}{4} &= \frac{y_2 - 5}{8}
\end{align*}

\textbf{Step 4: Solve for $y_2$}\\
Cross-multiply:
\begin{align*}
3 \times 8 &= 4 \times (y_2 - 5) \\
24 &= 4y_2 - 20 \\
24 + 20 &= 4y_2 \\
44 &= 4y_2 \\
y_2 &= 11
\end{align*}

\[\boxed{y_2 = 11}\]
\end{solutionbox}
\end{samepage}

