\section*{Worked Examples}
\nopagebreak[4]
\begin{samepage}
\begin{examplebox}{Calculating Percentage Increase in Cost}
An engineering project initially budgeted at \$500,000 experiences various unforeseen circumstances leading to a final cost of \$575,000. Calculate the percentage increase in the project cost.
\end{examplebox}

\begin{solutionbox}
\textbf{Solution Steps:}
\begin{enumerate}
  \item \textbf{Identify the change in cost.} \\
  Subtract the initial cost from the final cost. \\
  Formula: \text{Change in cost} = \text{Final cost} - \text{Initial cost} \\
  Calculation: \$575,000 - \$500,000 = \$75,000
  \item \textbf{Calculate the percentage increase.} \\
  Divide the change in cost by the initial cost and multiply by 100 to convert it to a percentage. \\
  Formula: \text{Percentage Increase} = \left(\frac{\text{Change in cost}}{\text{Initial cost}}\right) \times 100\% \\
  Calculation: \left(\frac{\$75,000}{\$500,000}\right) \times 100\% = 15\%
  \item \textbf{Finalize the calculation.} \\
  Ensure the calculation is correctly formatted and rounded if necessary. \\
  Formula: \text{Final percentage increase} = 15\% \\
  Calculation: 15\%
\end{enumerate}
\textbf{Final Answer:} \boxed{15\%}
\end{solutionbox}
\end{samepage}

\begin{samepage}
\begin{examplebox}{Using Decimals to Calculate Material Costs}
If 3.5 kg of a material costs \$7.75, calculate the cost for 5.5 kg of the same material using decimal multiplication.
\end{examplebox}

\begin{solutionbox}
\textbf{Solution Steps:}
\begin{enumerate}
  \item \textbf{Calculate the cost per kg.} \\
  Divide the total cost by the quantity to find the cost per kg. \\
  Formula: \text{Cost per kg} = \frac{\text{Total cost}}{\text{Quantity}} \\
  Calculation: \frac{\$7.75}{3.5\, \text{kg}} = \$2.21\, \text{per kg}
  \item \textbf{Calculate the total cost for 5.5 kg.} \\
  Multiply the cost per kg by the required quantity. \\
  Formula: \text{Total cost} = \text{Cost per kg} \times \text{Required quantity} \\
  Calculation: \$2.21 \times 5.5\, \text{kg} = \$12.16
  \item \textbf{Round the final answer if necessary.} \\
  Round the final answer to the nearest cent if dealing with currency. \\
  Formula: \text{Rounded total cost} = \$12.16 \\
  Calculation: \$12.16
\end{enumerate}
\textbf{Final Answer:} \boxed{\$12.16}
\end{solutionbox}
\end{samepage}

\begin{samepage}
\begin{examplebox}{Calculating Weighted Percentages for Composite Materials}
A composite material is made from 30\% steel (density 7.85 g/cm³), 60\% aluminum (density 2.70 g/cm³), and 10\% titanium (density 4.51 g/cm³). Calculate the average density of the composite material using weighted percentages.
\end{examplebox}

\begin{solutionbox}
\textbf{Solution Steps:}
\begin{enumerate}
  \item \textbf{Calculate the contribution of each material to the average density.} \\
  The average density can be calculated using the formula: \\
  \text{Average Density} = \left( \text{Density of Steel} \times \text{Fraction of Steel} \right) + \left( \text{Density of Aluminum} \times \text{Fraction of Aluminum} \right) + \left( \text{Density of Titanium} \times \text{Fraction of Titanium} \right)
  \item \textbf{Substituting the values:} \\
  \text{Average Density} = \left( 7.85 \, \text{g/cm}^3 \times 0.30 \right) + \left( 2.70 \, \text{g/cm}^3 \times 0.60 \right) + \left( 4.51 \, \text{g/cm}^3 \times 0.10 \right)
  \item \textbf{Calculate each term:} \\
  \text{Average Density} = 2.355 + 1.62 + 0.451 = 4.426 \, \text{g/cm}^3
\end{enumerate}
\textbf{Final Answer:} \boxed{4.43 \, \text{g/cm}^3}
\end{solutionbox}
\end{samepage}

