\section*{Worked Examples}
\nopagebreak[4]
\needspace{8\baselineskip}
\begin{samepage}
\begin{examplebox}{Worked Example 1: Basic Application of Factoring Techniques}
\textbf{Problem:} Factor the quadratic expression \( x^2 + 5x + 6 \). \\
\textbf{Given Information:} 
\begin{itemize}
    \item Expression: \( x^2 + 5x + 6 \)
\end{itemize}
\textbf{Required:} Factor completely.
\end{examplebox}

\begin{solutionbox}
\textbf{Solution Steps:}
\begin{itemize}
    \item \textbf{Step 1:} Identify the expression in the form \( ax^2 + bx + c \) \\
    Calculation: \( a=1, b=5, c=6 \)

    \item \textbf{Step 2:} Find two numbers that multiply to 6 and add to 5 \\
    Calculation: Numbers: 2 and 3

    \item \textbf{Step 3:} Rewrite the middle term using these numbers \\
    Calculation: \( x^2 + 2x + 3x + 6 \)

    \item \textbf{Step 4:} Factor by grouping \\
    Calculation: \( (x^2 + 2x) + (3x + 6) \)

    \item \textbf{Step 5:} Factor out common factors \\
    Calculation: \( x(x + 2) + 3(x + 2) \)

    \item \textbf{Step 6:} Factor out the common binomial \\
    Calculation: \( (x + 3)(x + 2) \)
\end{itemize}
\textbf{Final Answer:} \( (x + 3)(x + 2) \\
\textbf{Teaching Notes:} This example highlights basic factoring techniques and common pitfalls such as misidentifying factor pairs. \\
\textbf{Common Mistakes:} 
\begin{itemize}
    \item Using incorrect factor pairs due to sign errors
    \item Forgetting to factor completely
\end{itemize}
\end{solutionbox}
\end{samepage}

\nopagebreak[4]
\needspace{8\baselineskip}
\begin{samepage}
\begin{examplebox}{Worked Example 2: Intermediate Application of Factoring Techniques}
\textbf{Problem:} Factor the expression \( x^2 - 9 \) using the difference of squares. \\
\textbf{Given Information:} 
\begin{itemize}
    \item Expression: \( x^2 - 9 \)
\end{itemize}
\textbf{Required:} Factor completely.
\end{examplebox}

\begin{solutionbox}
\textbf{Solution Steps:}
\begin{itemize}
    \item \textbf{Step 1:} Recognize the expression as a difference of squares \\
    Calculation: \( x^2 - 9 = (x)^2 - (3)^2 \)

    \item \textbf{Step 2:} Apply the formula for difference of squares \\
    Calculation: \( (a^2 - b^2) = (a - b)(a + b) \)

    \item \textbf{Step 3:} Write the factored form \\
    Calculation: \( (x - 3)(x + 3) \)
\end{itemize}
\textbf{Final Answer:} \( (x - 3)(x + 3) \\
\textbf{Teaching Notes:} Emphasize recognizing patterns such as the difference of squares for quick factoring. \\
\textbf{Common Mistakes:} 
\begin{itemize}
    \item Misidentifying the expression type
    \item Incorrectly applying the difference of squares formula
\end{itemize}
\end{solutionbox}
\end{samepage}

\nopagebreak[4]
\needspace{8\baselineskip}
\begin{samepage}
\begin{examplebox}{Worked Example 3: Advanced Application of Factoring Techniques}
\textbf{Problem:} Solve the quadratic equation \( 2x^2 + 4x - 6 = 0 \) by completing the square. \\
\textbf{Given Information:} 
\begin{itemize}
    \item Equation: \( 2x^2 + 4x - 6 = 0 \)
\end{itemize}
\textbf{Required:} Solve for \( x \).
\end{examplebox}

\begin{solutionbox}
\textbf{Solution Steps:}
\begin{itemize}
    \item \textbf{Step 1:} Divide through by 2 to simplify \\
    Calculation: \( x^2 + 2x - 3 = 0 \)

    \item \textbf{Step 2:} Move the constant to the other side \\
    Calculation: \( x^2 + 2x = 3 \)

    \item \textbf{Step 3:} Complete the square by adding \( (b/2)^2 \) \\
    Calculation: \( (2/2)^2 = 1 \)

    \item \textbf{Step 4:} Rewrite as a perfect square \\
    Calculation: \( (x+1)^2 = 4 \)

    \item \textbf{Step 5:} Solve for \( x \) by taking the square root \\
    Calculation: \( x + 1 = \pm 2 \)

    \item \textbf{Step 6:} Solve the resulting linear equations \\
    Calculation: \( x = 1 \) or \( x = -3 \)
\end{itemize}
\textbf{Final Answer:} \( x = 1, -3 \\
\textbf{Teaching Notes:} This example illustrates the completing the square method, enhancing understanding of quadratic solutions. \\
\textbf{Common Mistakes:} 
\begin{itemize}
    \item Incorrectly completing the square
    \item Forgetting to apply the square root property correctly
\end{itemize}
\end{solutionbox}
\end{samepage}

