\node (pro3) [process, below=of pro2] {Rewrite Denominator};
\node (pro4) [process, below=of pro3] {Apply Division Rule};
\node (stop) [startstop, below=of pro4] {Final: $2^2 \cdot 5^6 = 62500$};

