\section*{Solutions to Exercises}
\nopagebreak[4]

\begin{samepage}
\needspace{10\baselineskip}
\begin{solutionbox}
\textbf{Exercise 1: Simplify $y^5 \cdot y^3$}\\[0.5em]
\textbf{Step 1: Identify the rule}\\
Both terms have the same base $y$. Apply the product of powers rule.
\begin{align*}
y^5 \cdot y^3 &= y^{5+3}
\end{align*}
\textbf{Step 2: Add the exponents}\\
\begin{align*}
y^{5+3} &= y^8
\end{align*}
\[\boxed{y^8}\]
\end{solutionbox}
\end{samepage}

\begin{samepage}
\needspace{10\baselineskip}
\begin{solutionbox}
\textbf{Exercise 2: Simplify $\dfrac{m^8}{m^3}$}\\[0.5em]
\textbf{Step 1: Identify the rule}\\
Both numerator and denominator have the same base $m$. Apply the quotient of powers rule.
\begin{align*}
\frac{m^8}{m^3} &= m^{8-3}
\end{align*}
\textbf{Step 2: Subtract the exponents}\\
\begin{align*}
m^{8-3} &= m^5
\end{align*}
\[\boxed{m^5}\]
\end{solutionbox}
\end{samepage}

\begin{samepage}
\needspace{10\baselineskip}
\begin{solutionbox}
\textbf{Exercise 3: Evaluate $3^2 \cdot 3^4$}\\[0.5em]
\textbf{Step 1: Apply the product rule}\\
\begin{align*}
3^2 \cdot 3^4 &= 3^{2+4} = 3^6
\end{align*}
\textbf{Step 2: Calculate the numerical value}\\
\begin{align*}
3^6 &= 729
\end{align*}
\[\boxed{3^6 = 729}\]
\end{solutionbox}
\end{samepage}

\begin{samepage}
\needspace{10\baselineskip}
\begin{solutionbox}
\textbf{Exercise 4: Simplify $(n^4)^3$}\\[0.5em]
\textbf{Step 1: Apply the power of a power rule}\\
When raising a power to another power, multiply the exponents.
\begin{align*}
(n^4)^3 &= n^{4 \times 3}
\end{align*}
\textbf{Step 2: Multiply the exponents}\\
\begin{align*}
n^{4 \times 3} &= n^{12}
\end{align*}
\[\boxed{n^{12}}\]
\end{solutionbox}
\end{samepage}

\begin{samepage}
\needspace{10\baselineskip}
\begin{solutionbox}
\textbf{Exercise 5: Simplify $(2x)^5$}\\[0.5em]
\textbf{Step 1: Apply the power of a product rule}\\
Distribute the exponent to each factor inside the parentheses.
\begin{align*}
(2x)^5 &= 2^5 \cdot x^5
\end{align*}
\textbf{Step 2: Calculate $2^5$}\\
\begin{align*}
2^5 &= 32
\end{align*}
\textbf{Step 3: Write the final answer}\\
\begin{align*}
(2x)^5 &= 32x^5
\end{align*}
\[\boxed{32x^5}\]
\end{solutionbox}
\end{samepage}

\begin{samepage}
\needspace{10\baselineskip}
\begin{solutionbox}
\textbf{Exercise 6: Simplify $\dfrac{6^7}{6^4 \cdot 6^2}$}\\[0.5em]
\textbf{Step 1: Simplify the denominator using the product rule}\\
\begin{align*}
6^4 \cdot 6^2 &= 6^{4+2} = 6^6
\end{align*}
\textbf{Step 2: Apply the quotient rule}\\
\begin{align*}
\frac{6^7}{6^6} &= 6^{7-6} = 6^1 = 6
\end{align*}
\[\boxed{6}\]
\end{solutionbox}
\end{samepage}

\begin{samepage}
\needspace{10\baselineskip}
\begin{solutionbox}
\textbf{Exercise 7: Simplify $\left(\dfrac{a^3}{b^2}\right)^4$}\\[0.5em]
\textbf{Step 1: Apply the power of a quotient rule}\\
Distribute the exponent to both numerator and denominator.
\begin{align*}
\left(\frac{a^3}{b^2}\right)^4 &= \frac{(a^3)^4}{(b^2)^4}
\end{align*}
\textbf{Step 2: Apply the power of a power rule to each part}\\
\begin{align*}
\frac{(a^3)^4}{(b^2)^4} &= \frac{a^{12}}{b^8}
\end{align*}
\[\boxed{\frac{a^{12}}{b^8}}\]
\end{solutionbox}
\end{samepage}

\begin{samepage}
\needspace{10\baselineskip}
\begin{solutionbox}
\textbf{Exercise 8: Simplify $\dfrac{(3^2 \cdot 7^3)^2}{21^2 \cdot 9^2}$}\\[0.5em]
\textbf{Step 1: Expand the numerator}\\
\begin{align*}
(3^2 \cdot 7^3)^2 &= 3^4 \cdot 7^6
\end{align*}
\textbf{Step 2: Rewrite the denominator using prime factorization}\\
\begin{align*}
21^2 &= (3 \cdot 7)^2 = 3^2 \cdot 7^2 \\
9^2 &= (3^2)^2 = 3^4
\end{align*}
So the denominator is $3^2 \cdot 7^2 \cdot 3^4 = 3^6 \cdot 7^2$.
\textbf{Step 3: Apply the quotient rule}\\
\begin{align*}
\frac{3^4 \cdot 7^6}{3^6 \cdot 7^2} &= 3^{4-6} \cdot 7^{6-2} = 3^{-2} \cdot 7^4 = \frac{7^4}{3^2} = \frac{2401}{9}
\end{align*}
\[\boxed{\frac{2401}{9}}\]
\end{solutionbox}
\end{samepage}

\begin{samepage}
\needspace{10\baselineskip}
\begin{solutionbox}
\textbf{Exercise 9: Find $\dfrac{2^{15}}{2^5}$ given $2^{10} = 1024$}\\[0.5em]
\textbf{Step 1: Apply the quotient rule}\\
\begin{align*}
\frac{2^{15}}{2^5} &= 2^{15-5} = 2^{10}
\end{align*}
\textbf{Step 2: Use the given information}\\
We are told that $2^{10} = 1024$.
\[\boxed{1024}\]
\end{solutionbox}
\end{samepage}

\begin{samepage}
\needspace{10\baselineskip}
\begin{solutionbox}
\textbf{Exercise 10: Simplify $\dfrac{(5^2 \cdot 2^3)^3}{(10^2)^2 \cdot 2}$}\\[0.5em]
\textbf{Step 1: Expand the numerator}\\
\begin{align*}
(5^2 \cdot 2^3)^3 &= 5^6 \cdot 2^9
\end{align*}
\textbf{Step 2: Expand the denominator}\\
\begin{align*}
(10^2)^2 \cdot 2 &= 10^4 \cdot 2 = (2 \cdot 5)^4 \cdot 2 = 2^4 \cdot 5^4 \cdot 2 = 2^5 \cdot 5^4
\end{align*}
\textbf{Step 3: Apply the quotient rule}\\
\begin{align*}
\frac{5^6 \cdot 2^9}{2^5 \cdot 5^4} &= 5^{6-4} \cdot 2^{9-5} = 5^2 \cdot 2^4 = 25 \cdot 16 = 400
\end{align*}
\[\boxed{400}\]
\end{solutionbox}
\end{samepage}

