\bottomrule
\end{tabular}
\end{table}

\end{examplebox}
\begin{solutionbox}
\textbf{Step 1: Identify the Slope-Intercept Form}\\
The slope-intercept form of a line is $y = mx + b$, where $m$ represents the slope of the line and $b$ is the y-intercept where the line crosses the $y$-axis.
\begin{align*}
\text{Formula: } y = mx + b
\end{align*}

\textbf{Step 2: Substitute the Given Values}\\
Use the point $(2, 3)$ and slope $m = 4$. Substitute $m$ into the formula, then substitute $x = 2$ and $y = 3$ to find $b$.
\begin{align*}
3 &= 4(2) + b \\
3 &= 8 + b \\
b &= 3 - 8 \\
b &= -5
\end{align*}

\textbf{Step 3: Write the Final Equation}\\
Substitute $m = 4$ and $b = -5$ into the equation to formulate the complete equation.
\begin{align*}
y = 4x - 5
\end{align*}

\[\boxed{y = 4x - 5}\]

\textit{Verification:} Substituting the point $(2, 3)$ back into the equation: $y = 4(2) - 5 = 8 - 5 = 3$ \checkmark
\end{solutionbox}
\begin{notebox}
\begin{itemize}
\item Slope-intercept form is essential for linear equations.
\item The slope indicates steepness and direction.
\item The y-intercept is where the line crosses the y-axis.
\end{itemize}
\end{notebox}
\end{samepage}

