\begin{solutionbox}
\textbf{Step 1: Identify Given Points}\\
Identify the coordinates of points $A$ and $B$. These points will be used to calculate the slope.
\begin{align*}
\text{Point } A&: (3, 4) \\
\text{Point } B&: (7, 10)
\end{align*}

\textbf{Step 2: Calculate the Slope}\\
Use the slope formula and substitute the coordinates of points $A$ and $B$.
\begin{align*}
m &= \frac{y_2 - y_1}{x_2 - x_1} \\
m &= \frac{10 - 4}{7 - 3} \\
m &= \frac{6}{4} \\
m &= 1.5
\end{align*}

\textbf{Step 3: Use Point-Slope Formula}\\
Use the point-slope form with point $A$ for substitution.
\begin{align*}
y - y_1 &= m(x - x_1) \\
y - 4 &= 1.5(x - 3) \\
y - 4 &= 1.5x - 4.5 \\
y &= 1.5x - 0.5
\end{align*}

\textbf{Step 4: Calculate the Y-Intercept}\\
Substitute $x = 0$ into the equation to find the y-intercept.
\begin{align*}
y &= 1.5(0) - 0.5 \\
y &= -0.5
\end{align*}

\textbf{Step 5: Rotation of the Line by 45 Degrees}\\
Apply the rotation matrix to transform the coordinates. For $\theta = 45°$:
\begin{align*}
\begin{pmatrix} x' \\ y' \end{pmatrix} &= \begin{pmatrix} \cos 45° & -\sin 45° \\ \sin 45° & \cos 45° \end{pmatrix} \begin{pmatrix} x \\ y \end{pmatrix} \\
&= \begin{pmatrix} \frac{\sqrt{2}}{2} & -\frac{\sqrt{2}}{2} \\ \frac{\sqrt{2}}{2} & \frac{\sqrt{2}}{2} \end{pmatrix} \begin{pmatrix} x \\ y \end{pmatrix}
\end{align*}

\textbf{Step 6: Calculate New Coordinates}\\
For point $A(3, 4)$:
\begin{align*}
x'_A &= \frac{\sqrt{2}}{2}(3) - \frac{\sqrt{2}}{2}(4) = \frac{\sqrt{2}}{2}(3-4) = -\frac{\sqrt{2}}{2} \approx -0.707 \\
y'_A &= \frac{\sqrt{2}}{2}(3) + \frac{\sqrt{2}}{2}(4) = \frac{\sqrt{2}}{2}(3+4) = \frac{7\sqrt{2}}{2} \approx 4.950
\end{align*}

For point $B(7, 10)$:
\begin{align*}
x'_B &= \frac{\sqrt{2}}{2}(7) - \frac{\sqrt{2}}{2}(10) = \frac{\sqrt{2}}{2}(7-10) = -\frac{3\sqrt{2}}{2} \approx -2.121 \\
y'_B &= \frac{\sqrt{2}}{2}(7) + \frac{\sqrt{2}}{2}(10) = \frac{\sqrt{2}}{2}(17) = \frac{17\sqrt{2}}{2} \approx 12.021
\end{align*}

\textbf{Step 7: Calculate New Slope and Equation}\\
Using the transformed points $A'(-0.707, 4.950)$ and $B'(-2.121, 12.021)$:
\begin{align*}
m' &= \frac{12.021 - 4.950}{-2.121 - (-0.707)} = \frac{7.071}{-1.414} = -5
\end{align*}

Using point-slope form with $A'$:
\begin{align*}
y - 4.950 &= -5(x - (-0.707)) \\
y &= -5x - 3.535 + 4.950 \\
y &= -5x + 1.414
\end{align*}

\textbf{Step 8: Verification}\\
The original equation passes through both given points. The rotated line equation can be verified by substituting the transformed coordinates.

\[\boxed{\text{Original: } y = 1.5x - 0.5; \quad \text{Rotated: } y \approx -5x + 1.414}\]
\end{solutionbox}
