\section*{Exercises}
\nopagebreak[4]

\begin{samepage}
\textbf{1.} Find the equation of the line passing through the point $(1, 5)$ with a slope of $-2$. Express your answer in slope-intercept form.
\end{samepage}

\begin{samepage}
\textbf{2.} Determine the equation of the line that passes through the points $(0, 4)$ and $(3, 10)$.
\end{samepage}

\begin{samepage}
\textbf{3.} A line has a y-intercept of $-3$ and passes through the point $(4, 5)$. Find the slope of the line and write its equation.
\end{samepage}

\begin{samepage}
\textbf{4.} An engineer designs a drainage channel that drops 2 meters over a horizontal distance of 50 meters. If the channel starts at an elevation of 15 meters, write the equation describing the channel's profile.
\end{samepage}

\begin{samepage}
\textbf{5.} Find the equation of the line passing through $(-2, 3)$ and $(4, -9)$. At what point does this line cross the x-axis?
\end{samepage}

\begin{samepage}
\textbf{6.} A cable car travels along a straight path from station $A$ at coordinates $(100, 250)$ meters to station $B$ at coordinates $(400, 550)$ meters. Determine the equation of the cable car's path.
\end{samepage}

\begin{samepage}
\textbf{7.} The temperature $T$ (in °C) of a cooling object varies linearly with time $t$ (in minutes). At $t = 5$ minutes, $T = 80°$C, and at $t = 20$ minutes, $T = 35°$C. Find the equation relating $T$ and $t$, and determine the initial temperature at $t = 0$.
\end{samepage}

\begin{samepage}
\textbf{8.} A line passes through the point $(5, 7)$ and is parallel to the line $y = \frac{2}{3}x - 4$. Find the equation of this line.
\end{samepage}

\begin{samepage}
\textbf{9.} Find the equation of the line passing through the points $P(2, -1)$ and $Q(8, 11)$. If this line is translated 3 units upward, what is the new equation?
