\section*{Solutions to Exercises}
\nopagebreak[4]

\begin{samepage}
\needspace{10\baselineskip}
\begin{solutionbox}
\textbf{Exercise 1: Line through $(1, 5)$ with slope $-2$}\\[0.5em]
\textbf{Step 1: Apply the point-slope form}\\
Using the point-slope formula with $(x_1, y_1) = (1, 5)$ and $m = -2$:
\begin{align*}
y - y_1 &= m(x - x_1) \\
y - 5 &= -2(x - 1)
\end{align*}
\textbf{Step 2: Convert to slope-intercept form}\\
Distribute and solve for $y$:
\begin{align*}
y - 5 &= -2x + 2 \\
y &= -2x + 2 + 5 \\
y &= -2x + 7
\end{align*}
\[\boxed{y = -2x + 7}\]
\end{solutionbox}
\end{samepage}

\begin{samepage}
\needspace{10\baselineskip}
\begin{solutionbox}
\textbf{Exercise 2: Line through $(0, 4)$ and $(3, 10)$}\\[0.5em]
\textbf{Step 1: Calculate the slope}\\
Using the slope formula:
\begin{align*}
m &= \frac{y_2 - y_1}{x_2 - x_1} = \frac{10 - 4}{3 - 0} = \frac{6}{3} = 2
\end{align*}
\textbf{Step 2: Identify the y-intercept}\\
Since the line passes through $(0, 4)$, the y-intercept is $b = 4$.
\begin{align*}
y &= mx + b = 2x + 4
\end{align*}
\[\boxed{y = 2x + 4}\]
\end{solutionbox}
\end{samepage}

\begin{samepage}
\needspace{10\baselineskip}
\begin{solutionbox}
\textbf{Exercise 3: Line with y-intercept $-3$ through $(4, 5)$}\\[0.5em]
\textbf{Step 1: Set up the equation}\\
The y-intercept gives us $b = -3$, so the equation has the form $y = mx - 3$.
\begin{align*}
y &= mx - 3
\end{align*}
\textbf{Step 2: Substitute the point to find $m$}\\
Substituting $(4, 5)$:
\begin{align*}
5 &= m(4) - 3 \\
5 + 3 &= 4m \\
8 &= 4m \\
m &= 2
\end{align*}
\textbf{Step 3: Write the final equation}
\begin{align*}
y &= 2x - 3
\end{align*}
\[\boxed{m = 2; \quad y = 2x - 3}\]
\end{solutionbox}
\end{samepage}

\begin{samepage}
\needspace{10\baselineskip}
\begin{solutionbox}
\textbf{Exercise 4: Drainage channel profile}\\[0.5em]
\textbf{Step 1: Identify the coordinates}\\
Starting point: $(0, 15)$ (horizontal distance 0, elevation 15 m).\\
Ending point: $(50, 13)$ (drops 2 m over 50 m horizontal distance).
\begin{align*}
\text{Point 1: } &(0, 15) \\
\text{Point 2: } &(50, 13)
\end{align*}
\textbf{Step 2: Calculate the slope}
\begin{align*}
m &= \frac{13 - 15}{50 - 0} = \frac{-2}{50} = -0.04
\end{align*}
\textbf{Step 3: Write the equation}\\
Since the line passes through $(0, 15)$, the y-intercept is 15.
\begin{align*}
y &= -0.04x + 15
\end{align*}
\[\boxed{y = -0.04x + 15}\]
\end{solutionbox}
\end{samepage}

\begin{samepage}
\needspace{10\baselineskip}
\begin{solutionbox}
\textbf{Exercise 5: Line through $(-2, 3)$ and $(4, -9)$}\\[0.5em]
\textbf{Step 1: Calculate the slope}
\begin{align*}
m &= \frac{-9 - 3}{4 - (-2)} = \frac{-12}{6} = -2
\end{align*}
\textbf{Step 2: Use point-slope form}\\
Using point $(-2, 3)$:
\begin{align*}
y - 3 &= -2(x - (-2)) \\
y - 3 &= -2(x + 2) \\
y - 3 &= -2x - 4 \\
y &= -2x - 1
\end{align*}
\textbf{Step 3: Find the x-intercept}\\
Set $y = 0$:
\begin{align*}
0 &= -2x - 1 \\
2x &= -1 \\
x &= -0.5
\end{align*}
\[\boxed{y = -2x - 1; \quad \text{x-intercept: } (-0.5, 0)}\]
\end{solutionbox}
\end{samepage}

\begin{samepage}
\needspace{10\baselineskip}
\begin{solutionbox}
\textbf{Exercise 6: Cable car path from $A(100, 250)$ to $B(400, 550)$}\\[0.5em]
\textbf{Step 1: Calculate the slope}
\begin{align*}
m &= \frac{550 - 250}{400 - 100} = \frac{300}{300} = 1
\end{align*}
\textbf{Step 2: Use point-slope form}\\
Using point $A(100, 250)$:
\begin{align*}
y - 250 &= 1(x - 100) \\
y - 250 &= x - 100 \\
y &= x + 150
\end{align*}
\[\boxed{y = x + 150}\]
\end{solutionbox}
\end{samepage}

\begin{samepage}
\needspace{10\baselineskip}
\begin{solutionbox}
\textbf{Exercise 7: Cooling object temperature}\\[0.5em]
\textbf{Step 1: Identify the points}\\
Point 1: $(5, 80)$ and Point 2: $(20, 35)$, where $t$ is time and $T$ is temperature.
\begin{align*}
\text{Point 1: } &(5, 80) \\
\text{Point 2: } &(20, 35)
\end{align*}
\textbf{Step 2: Calculate the slope}
\begin{align*}
m &= \frac{35 - 80}{20 - 5} = \frac{-45}{15} = -3
\end{align*}
\textbf{Step 3: Find the equation}\\
Using point $(5, 80)$:
\begin{align*}
T - 80 &= -3(t - 5) \\
T - 80 &= -3t + 15 \\
T &= -3t + 95
\end{align*}
\textbf{Step 4: Find initial temperature at $t = 0$}
\begin{align*}
T(0) &= -3(0) + 95 = 95°\text{C}
\end{align*}
\[\boxed{T = -3t + 95; \quad T(0) = 95°\text{C}}\]
\end{solutionbox}
\end{samepage}

\begin{samepage}
\needspace{10\baselineskip}
\begin{solutionbox}
\textbf{Exercise 8: Line through $(5, 7)$ parallel to $y = \frac{2}{3}x - 4$}\\[0.5em]
\textbf{Step 1: Identify the slope}\\
Parallel lines have equal slopes. The given line has slope $m = \frac{2}{3}$.
\begin{align*}
m &= \frac{2}{3}
\end{align*}
\textbf{Step 2: Use point-slope form}\\
Using point $(5, 7)$:
\begin{align*}
y - 7 &= \frac{2}{3}(x - 5) \\
y - 7 &= \frac{2}{3}x - \frac{10}{3} \\
y &= \frac{2}{3}x - \frac{10}{3} + 7 \\
y &= \frac{2}{3}x - \frac{10}{3} + \frac{21}{3} \\
y &= \frac{2}{3}x + \frac{11}{3}
\end{align*}
\[\boxed{y = \frac{2}{3}x + \frac{11}{3}}\]
\end{solutionbox}
\end{samepage}

\begin{samepage}
\needspace{10\baselineskip}
\begin{solutionbox}
\textbf{Exercise 9: Line through $P(2, -1)$ and $Q(8, 11)$, then translated}\\[0.5em]
\textbf{Step 1: Calculate the slope}
\begin{align*}
m &= \frac{11 - (-1)}{8 - 2} = \frac{12}{6} = 2
\end{align*}
\textbf{Step 2: Find the original equation}\\
Using point $P(2, -1)$:
\begin{align*}
y - (-1) &= 2(x - 2) \\
y + 1 &= 2x - 4 \\
y &= 2x - 5
\end{align*}
\textbf{Step 3: Apply the translation}\\
Translating 3 units upward adds 3 to the y-intercept:
\begin{align*}
y &= 2x - 5 + 3 \\
y &= 2x - 2
\end{align*}
\[\boxed{\text{Original: } y = 2x - 5; \quad \text{Translated: } y = 2x - 2}\]
\end{solutionbox}
\end{samepage}

\begin{samepage}
\needspace{10\baselineskip}
\begin{solutionbox}
\textbf{Exercise 10: Beam through $(0, 3)$ and $(6, 9)$ rotated $90°$}\\[0.5em]
\textbf{Step 1: Find the original equation}\\
Slope: $m = \frac{9-3}{6-0} = 1$. Y-intercept: $b = 3$.
\begin{align*}
y &= x + 3
\end{align*}
\textbf{Step 2: Apply the rotation matrix for $90°$}\\
For $\theta = 90°$: $\cos 90° = 0$, $\sin 90° = 1$.
\begin{align*}
\begin{pmatrix} x' \\ y' \end{pmatrix} &= \begin{pmatrix} 0 & -1 \\ 1 & 0 \end{pmatrix} \begin{pmatrix} x \\ y \end{pmatrix}
\end{align*}
\textbf{Step 3: Transform the points}\\
Point $(0, 3)$: $x' = 0(0) - 1(3) = -3$, $y' = 1(0) + 0(3) = 0$. New point: $(-3, 0)$.\\
Point $(6, 9)$: $x' = 0(6) - 1(9) = -9$, $y' = 1(6) + 0(9) = 6$. New point: $(-9, 6)$.
\begin{align*}
\text{Transformed points: } &(-3, 0) \text{ and } (-9, 6)
\end{align*}
\textbf{Step 4: Find the new equation}
\begin{align*}
m' &= \frac{6 - 0}{-9 - (-3)} = \frac{6}{-6} = -1
\end{align*}
Using point $(-3, 0)$:
\begin{align*}
y - 0 &= -1(x - (-3)) \\
y &= -1(x + 3) \\
y &= -x - 3
\end{align*}
\[\boxed{y = -x - 3}\]
\end{solutionbox}
\end{samepage}

