$P(-2, -1)$ and $Q(4, -1)$:
\begin{align*}
d_{PQ} &= \sqrt{(4-(-2))^2 + (-1-(-1))^2} = \sqrt{36 + 0} = 6
\end{align*}

\textbf{Step 2: Calculate $QR$ (right side)}\\
$Q(4, -1)$ and $R(4, 3)$:
\begin{align*}
d_{QR} &= \sqrt{(4-4)^2 + (3-(-1))^2} = \sqrt{0 + 16} = 4
\end{align*}

\textbf{Step 3: Calculate $RS$ (top side)}\\
$R(4, 3)$ and $S(-2, 3)$:
\begin{align*}
d_{RS} &= \sqrt{(-2-4)^2 + (3-3)^2} = \sqrt{36 + 0} = 6
\end{align*}

\textbf{Step 4: Calculate $SP$ (left side)}\\
$S(-2, 3)$ and $P(-2, -1)$:
\begin{align*}
d_{SP} &= \sqrt{(-2-(-2))^2 + (-1-3)^2} = \sqrt{0 + 16} = 4
\end{align*}

\textbf{Step 5: Verify opposite sides are equal}\\
$PQ = RS = 6$ and $QR = SP = 4$. Opposite sides are equal.

\[\boxed{PQ = RS = 6 \text{ units; } QR = SP = 4 \text{ units}}\]
\end{solutionbox}
\end{samepage}

\begin{samepage}
\needspace{10\baselineskip}
\begin{solutionbox}
\textbf{Exercise 9: Finding $x$ When Distance is Known}\\[0.5em]
\textbf{Step 1: Set up the distance equation}\\
$A(2, 3)$ and $B(x, 7)$ with $d = 5$:
\begin{align*}
5 &= \sqrt{(x - 2)^2 + (7 - 3)^2}
\end{align*}

\textbf{Step 2: Square both sides}
\begin{align*}
25 &= (x - 2)^2 + 16
\end{align*}

\textbf{Step 3: Solve for $(x-2)^2$}
\begin{align*}
(x - 2)^2 &= 25 - 16 = 9
\end{align*}

\textbf{Step 4: Take the square root}
\begin{align*}
x - 2 &= \pm 3
\end{align*}

\textbf{Step 5: Solve for $x$}
\begin{align*}
x &= 2 + 3 = 5 \quad \text{or} \quad x = 2 - 3 = -1
\end{align*}

\[\boxed{x = 5 \text{ or } x = -1}\]
\end{solutionbox}
\end{samepage}

\begin{samepage}
\needspace{10\baselineskip}
\begin{solutionbox}
\textbf{Exercise 10: Total Cable Length for Relay Stations}\\[0.5em]
\textbf{Step 1: Calculate distance $AB$}\\
$A(0, 0)$ and $B(8, 6)$:
\begin{align*}
d_{AB} &= \sqrt{(8-0)^2 + (6-0)^2} = \sqrt{64 + 36} = \sqrt{100} = 10
\end{align*}

\textbf{Step 2: Calculate distance $BC$}\\
$B(8, 6)$ and $C(12, 0)$:
\begin{align*}
d_{BC} &= \sqrt{(12-8)^2 + (0-6)^2} = \sqrt{16 + 36} = \sqrt{52} \approx 7.21
\end{align*}

\textbf{Step 3: Calculate total cable length}
\begin{align*}
\text{Total} &= d_{AB} + d_{BC} = 10 + \sqrt{52} = 10 + 2\sqrt{13} \approx 17.21
\end{align*}

\[\boxed{\text{Total cable length} = 10 + 2\sqrt{13} \approx 17.21 \text{ units}}\]
\end{solutionbox}
\end{samepage}

