\section*{Worked Examples}

\begin{samepage}
\needspace{8\baselineskip}
\begin{examplebox}{Calculating Mechanical Advantage Using Ratios}
\nopagebreak[4]
Determine the mechanical advantage of a lever where the distance from the fulcrum to the effort point is 2 meters and to the load point is 0.5 meters.
\end{examplebox}

\begin{solutionbox}
\nopagebreak[4]
\textbf{Given Information:}
\begin{itemize}
  \item Distance from the fulcrum to the effort point: $2 \text{ meters}$
  \item Distance from the fulcrum to the load point: $0.5 \text{ meters}$
\end{itemize}

\textbf{Required:} Mechanical advantage of the lever

\textbf{Solution Steps:}
\begin{enumerate}
  \item \textbf{Set up the ratio of distances for mechanical advantage.}
  \begin{itemize}
    \item The mechanical advantage (MA) of a lever is the ratio of the distance from the fulcrum to the effort (d1) to the distance from the fulcrum to the load (d2).
    \item Formula: $\text{MA} = \frac{d1}{d2}$
  \end{itemize}

  \item \textbf{Calculate the mechanical advantage.}
  \begin{itemize}
    \item Using the ratio of distances, the mechanical advantage is calculated.
    \item Formula: $\text{MA} = \frac{2 \text{ meters}}{0.5 \text{ meters}}$
    \item Calculation: $\text{MA} = 4$
  \end{itemize}
\end{enumerate}

\textbf{Final Answer:} \(\boxed{4}\) The mechanical advantage of the lever is 4, meaning the effort force can be four times less than the load for balance.

\textbf{Teaching Notes:} Common mistake: confusing the positions of d1 and d2. Always ensure that d1 is the distance to the effort point and d2 to the load to correctly calculate the mechanical advantage.
\end{solutionbox}
\end{samepage}

\begin{samepage}
\needspace{8\baselineskip}
\begin{examplebox}{Computing Flow Rates in Pipes}
\nopagebreak[4]
Calculate the flow rate of water through a pipe with a diameter of 0.5 meters if the velocity of water is 3 meters per second.
\end{examplebox}

\begin{solutionbox}
\nopagebreak[4]
\textbf{Given Information:}
\begin{itemize}
  \item Diameter of the pipe: $0.5 \text{ meters}$
  \item Velocity of water: $3 \text{ meters/second}$
\end{itemize}

\textbf{Required:} Flow rate of water in cubic meters per second

\textbf{Solution Steps:}
\begin{enumerate}
  \item \textbf{Calculate the cross-sectional area of the pipe.}
  \begin{itemize}
    \item The flow rate can be determined by multiplying the cross-sectional area of the pipe by the velocity of the water. The area of a circle is given by $\pi r^2$.
    \item Formula: $\text{Area} = \pi r^2$
    \item Calculation: $\text{Area} = \pi \left(\frac{0.5}{2}\right)^2 = 0.19635 \text{ m}^2$
  \end{itemize}

  \item \textbf{Multiply the area by the velocity to find the flow rate.}
  \begin{itemize}
    \item The flow rate is the product of the cross-sectional area and the velocity of the water.
    \item Formula: $\text{Flow Rate} = \text{Area} \times \text{Velocity}$
    \item Calculation: $\text{Flow Rate} = 0.19635 \text{ m}^2 \times 3 \text{ m/s} = 0.58905 \text{ m}^3/s$
  \end{itemize}
\end{enumerate}

\textbf{Final Answer:} The flow rate of water through the pipe is approximately \(0.589 \text{ m}^3/s\).
\end{solutionbox}
\end{samepage}

